 40	func (s *NezhaHandler) RequestTask(stream pb.NezhaService_RequestTaskServer) error {
 41		var clientID uint64
 42		var err error
 43		if clientID, err = s.Auth.Check(stream.Context()); err != nil {
 44			return err
 45		}
 46	
 47		server, _ := singleton.ServerShared.Get(clientID)
 48		server.TaskStream = stream
 49		var result *pb.TaskResult
 50		for {
 51			result, err = stream.Recv()
 52			if err != nil {
 53				log.Printf("NEZHA>> RequestTask error: %v, clientID: %d\n", err, clientID)
 54				return err
 55			}
 56			switch result.GetType() {
 57			case model.TaskTypeCommand:
 58				// 处理上报的计划任务
 59				cr, _ := singleton.CronShared.Get(result.GetId())
 60				if cr != nil {
 61					// 保存当前服务器状态信息
 62					var curServer model.Server
 63					copier.Copy(&curServer, server)
 64					if cr.PushSuccessful && result.GetSuccessful() {
 65						singleton.NotificationShared.SendNotification(cr.NotificationGroupID, fmt.Sprintf("[%s] %s, %s\n%s", singleton.Localizer.T("Scheduled Task Executed Successfully"),
 66							cr.Name, server.Name, result.GetData()), "", &curServer)
 67					}
 68					if !result.GetSuccessful() {
 69						singleton.NotificationShared.SendNotification(cr.NotificationGroupID, fmt.Sprintf("[%s] %s, %s\n%s", singleton.Localizer.T("Scheduled Task Executed Failed"),
 70							cr.Name, server.Name, result.GetData()), "", &curServer)
 71					}
 72					singleton.DB.Model(cr).Updates(model.Cron{
 73						LastExecutedAt: time.Now().Add(time.Second * -1 * time.Duration(result.GetDelay())),
 74						LastResult:     result.GetSuccessful(),
 75					})
 76				}
 77			case model.TaskTypeReportConfig:
 78				if len(server.ConfigCache) < 1 {
 79					if !result.GetSuccessful() {
 80						server.ConfigCache <- errors.New(result.Data)
 81						continue
 82					}
 83					server.ConfigCache <- result.Data
 84				}
 85			default:
 86				if model.IsServiceSentinelNeeded(result.GetType()) {
 87					singleton.ServiceSentinelShared.Dispatch(singleton.ReportData{
 88						Data:     result,
 89						Reporter: clientID,
 90					})
 91				}
 92			}
 93		}
 94	}
