 71	func (c *CronClass) Update(cr *model.Cron) {
 72		c.listMu.Lock()
 73		crOld := c.list[cr.ID]
 74		if crOld != nil && crOld.CronJobID != 0 {
 75			c.Cron.Remove(crOld.CronJobID)
 76		}
 77	
 78		delete(c.list, cr.ID)
 79		c.list[cr.ID] = cr
 80		c.listMu.Unlock()
 81	
 82		c.sortList()
 83	}
