113	func (c *CronClass) SendTriggerTasks(taskIDs []uint64, triggerServer uint64, triggerOwner uint64) {
114		c.listMu.RLock()
115		var cronLists []*model.Cron
116		for _, taskID := range taskIDs {
117			if c, ok := c.list[taskID]; ok && cronCanBeTriggeredByOwner(c, triggerOwner) {
118				cronLists = append(cronLists, c)
119			}
120		}
121		c.listMu.RUnlock()
122	
123		// 依次调用CronTrigger发送任务
124		for _, c := range cronLists {
125			go CronTrigger(c, triggerServer)()
126		}
127	}
