137	func CronTrigger(cr *model.Cron, triggerServer ...uint64) func() {
138		crIgnoreMap := make(map[uint64]bool)
139		for _, server := range cr.Servers {
140			crIgnoreMap[server] = true
141		}
142		return func() {
143			if cr.Cover == model.CronCoverAlertTrigger {
144				if len(triggerServer) == 0 {
145					return
146				}
147				if s, ok := ServerShared.Get(triggerServer[0]); ok {
148					if !cronCanSendToServer(cr, s) {
149						return
150					}
151					if s.TaskStream != nil {
152						s.TaskStream.Send(&pb.Task{
153							Id:   cr.ID,
154							Data: cr.Command,
155							Type: model.TaskTypeCommand,
156						})
157					} else {
158						// 保存当前服务器状态信息
159						curServer := model.Server{}
160						copier.Copy(&curServer, s)
161						go NotificationShared.SendNotification(cr.NotificationGroupID, Localizer.Tf("[Task failed] %s: server %s is offline and cannot execute the task", cr.Name, s.Name), "", &curServer)
162					}
163				}
164				return
165			}
166	
167			for _, s := range ServerShared.Range {
168				if !cronCanSendToServer(cr, s) {
169					continue
170				}
171				if cr.Cover == model.CronCoverAll && crIgnoreMap[s.ID] {
172					continue
173				}
174				if cr.Cover == model.CronCoverIgnoreAll && !crIgnoreMap[s.ID] {
175					continue
176				}
177				if s.TaskStream != nil {
178					s.TaskStream.Send(&pb.Task{
179						Id:   cr.ID,
180						Data: cr.Command,
181						Type: model.TaskTypeCommand,
182					})
183				} else {
184					// 保存当前服务器状态信息
185					curServer := model.Server{}
186					copier.Copy(&curServer, s)
187					go NotificationShared.SendNotification(cr.NotificationGroupID, Localizer.Tf("[Task failed] %s: server %s is offline and cannot execute the task", cr.Name, s.Name), "", &curServer)
188				}
189			}
190		}
191	}
