278	func (ss *ServiceSentinel) loadTodayStats(today time.Time) {
279		if TSDBEnabled() {
280			for serviceID, ms := range ss.monthlyStatus {
281				result, err := TSDBShared.QueryServiceHistory(serviceID, tsdb.Period1Day)
282				if err != nil {
283					log.Printf("NEZHA>> Failed to load TSDB today stats for service %d: %v", serviceID, err)
284					continue
285				}
286				var totalUp, totalDown uint64
287				var totalDelay float64
288				var delayCount int
289				for _, serverStats := range result.Servers {
290					totalUp += serverStats.Stats.TotalUp
291					totalDown += serverStats.Stats.TotalDown
292					if serverStats.Stats.AvgDelay > 0 {
293						totalDelay += serverStats.Stats.AvgDelay
294						delayCount++
295					}
296				}
297				ss.serviceStatusToday[serviceID].Up = totalUp
298				ss.serviceStatusToday[serviceID].Down = totalDown
299				if delayCount > 0 {
300					ss.serviceStatusToday[serviceID].Delay = totalDelay / float64(delayCount)
301				}
302				ms.TotalUp += totalUp
303				ms.TotalDown += totalDown
304			}
305		} else {
306			var mhs []model.ServiceHistory
307			DB.Where("created_at >= ? AND server_id = 0", today).Find(&mhs)
308			totalDelay := make(map[uint64]float64)
309			totalDelayCount := make(map[uint64]int)
310			for _, mh := range mhs {
311				ss.serviceStatusToday[mh.ServiceID].Up += mh.Up
312				ss.monthlyStatus[mh.ServiceID].TotalUp += mh.Up
313				ss.serviceStatusToday[mh.ServiceID].Down += mh.Down
314				ss.monthlyStatus[mh.ServiceID].TotalDown += mh.Down
315				totalDelay[mh.ServiceID] += mh.AvgDelay
316				totalDelayCount[mh.ServiceID]++
317			}
318			for id, delay := range totalDelay {
319				ss.serviceStatusToday[id].Delay = delay / float64(totalDelayCount[id])
320			}
321		}
322	}
