324	func (ss *ServiceSentinel) Update(m *model.Service) error {
325		ss.serviceResponseDataStoreLock.Lock()
326		defer ss.serviceResponseDataStoreLock.Unlock()
327		ss.monthlyStatusLock.Lock()
328		defer ss.monthlyStatusLock.Unlock()
329		ss.servicesLock.Lock()
330		defer ss.servicesLock.Unlock()
331	
332		var err error
333		// 写入新任务
334		m.CronJobID, err = CronShared.AddFunc(m.CronSpec(), func() {
335			ss.dispatchBus <- m
336		})
337		if err != nil {
338			return err
339		}
340		if ss.services[m.ID] != nil {
341			// 停掉旧任务
342			CronShared.Remove(ss.services[m.ID].CronJobID)
343		} else {
344			// 新任务初始化数据
345			ss.monthlyStatus[m.ID] = &serviceResponseItem{
346				service: m,
347				ServiceResponseItem: model.ServiceResponseItem{
348					Delay: &[30]float64{},
349					Up:    &[30]uint64{},
350					Down:  &[30]uint64{},
351				},
352			}
353			if ss.serviceCurrentStatusData[m.ID] == nil {
354				ss.serviceCurrentStatusData[m.ID] = new(serviceTaskStatus)
355			}
356			ss.serviceCurrentStatusData[m.ID].result = make([]*pb.TaskResult, 0, _CurrentStatusSize)
357			ss.serviceStatusToday[m.ID] = &_TodayStatsOfService{}
358		}
359		// 更新这个任务
360		ss.services[m.ID] = m
361		return nil
362	}
