386	func (ss *ServiceSentinel) LoadStats() map[uint64]*serviceResponseItem {
387		ss.servicesLock.RLock()
388		defer ss.servicesLock.RUnlock()
389		ss.serviceResponseDataStoreLock.RLock()
390		defer ss.serviceResponseDataStoreLock.RUnlock()
391		ss.monthlyStatusLock.Lock()
392		defer ss.monthlyStatusLock.Unlock()
393	
394		// 刷新最新一天的数据
395		for k := range ss.services {
396			ss.monthlyStatus[k].service = ss.services[k]
397			v := ss.serviceStatusToday[k]
398	
399			// 30 天在线率，
400			//   |- 减去上次加的旧当天数据，防止出现重复计数
401			ss.monthlyStatus[k].TotalUp -= ss.monthlyStatus[k].Up[29]
402			ss.monthlyStatus[k].TotalDown -= ss.monthlyStatus[k].Down[29]
403			//   |- 加上当日数据
404			ss.monthlyStatus[k].TotalUp += v.Up
405			ss.monthlyStatus[k].TotalDown += v.Down
406	
407			ss.monthlyStatus[k].Up[29] = v.Up
408			ss.monthlyStatus[k].Down[29] = v.Down
409			ss.monthlyStatus[k].Delay[29] = v.Delay
410		}
411	
412		// 最后 5 分钟的状态 与 service 对象填充
413		for k, v := range ss.serviceResponseDataStore {
414			ss.monthlyStatus[k].CurrentDown = v.Down
415			ss.monthlyStatus[k].CurrentUp = v.Up
416		}
417	
418		return ss.monthlyStatus
419	}
