475	// worker 服务监控的实际工作流程
476	func (ss *ServiceSentinel) worker() {
477		// 从服务状态汇报管道获取汇报的服务数据
478		for r := range ss.serviceReportChannel {
479			css, _ := ss.Get(r.Data.GetId())
480			if css == nil || css.ID == 0 {
481				log.Printf("NEZHA>> Incorrect service monitor report %+v", r)
482				continue
483			}
484			css = nil
485	
486			mh := r.Data
487			if mh.Type == model.TaskTypeTCPPing || mh.Type == model.TaskTypeICMPPing {
488				// TCP/ICMP Ping 使用平均值计算后再写入
489				serviceTcpMap, ok := ss.serviceResponsePing[mh.GetId()]
490				if !ok {
491					serviceTcpMap = make(map[uint64]*pingStore)
492					ss.serviceResponsePing[mh.GetId()] = serviceTcpMap
493				}
494				ts, ok := serviceTcpMap[r.Reporter]
495				if !ok {
496					ts = &pingStore{}
497				}
498				ts.count++
499				ts.ping = (ts.ping*float64(ts.count-1) + float64(mh.Delay)) / float64(ts.count)
500				if mh.Successful {
501					ts.successCount++
502				}
503				if ts.count == Conf.AvgPingCount {
504					if TSDBEnabled() {
505						if err := TSDBShared.WriteServiceMetrics(&tsdb.ServiceMetrics{
506							ServiceID:  mh.GetId(),
507							ServerID:   r.Reporter,
508							Timestamp:  time.Now(),
509							Delay:      ts.ping,
510							Successful: ts.successCount*2 >= ts.count,
511						}); err != nil {
512							log.Printf("NEZHA>> Failed to save service monitor metrics to TSDB: %v", err)
513						}
514					} else {
515						if err := DB.Create(&model.ServiceHistory{
516							ServiceID: mh.GetId(),
517							AvgDelay:  ts.ping,
518							Data:      mh.Data,
519							ServerID:  r.Reporter,
520						}).Error; err != nil {
521							log.Printf("NEZHA>> Failed to save service monitor metrics: %v", err)
522						}
523					}
524					ts.count = 0
525					ts.ping = 0
526					ts.successCount = 0
527				}
528				serviceTcpMap[r.Reporter] = ts
529			} else {
530				if TSDBEnabled() {
531					if err := TSDBShared.WriteServiceMetrics(&tsdb.ServiceMetrics{
