100	// RecordTransferHourlyUsage 对流量记录进行打点
101	func RecordTransferHourlyUsage(servers ...*model.Server) {
102		now := time.Now()
103		nowTrimSeconds := time.Date(now.Year(), now.Month(), now.Day(), now.Hour(), 0, 0, 0, now.Location())
104	
105		var txs []model.Transfer
106		var slist iter.Seq[*model.Server]
107		if len(servers) > 0 {
108			slist = slices.Values(servers)
109		} else {
110			slist = utils.Seq2To1(ServerShared.Range)
111		}
112	
113		for server := range slist {
114			tx := model.Transfer{
115				ServerID: server.ID,
116				In:       utils.SubUintChecked(server.State.NetInTransfer, server.PrevTransferInSnapshot),
117				Out:      utils.SubUintChecked(server.State.NetOutTransfer, server.PrevTransferOutSnapshot),
118			}
119			if tx.In == 0 && tx.Out == 0 {
120				continue
121			}
122			server.PrevTransferInSnapshot = server.State.NetInTransfer
123			server.PrevTransferOutSnapshot = server.State.NetOutTransfer
124			tx.CreatedAt = nowTrimSeconds
125			txs = append(txs, tx)
126		}
127	
128		if len(txs) == 0 {
129			return
130		}
131		log.Printf("NEZHA>> Saved traffic metrics to database. Affected %d row(s), Error: %v", len(txs), DB.Create(txs).Error)
132	}
