135	func CleanMonitorHistory() {
136		// 清理已被删除的服务器的流量记录
137		DB.Unscoped().Delete(&model.Transfer{}, "server_id NOT IN (SELECT `id` FROM servers)")
138		// 计算可清理流量记录的时长
139		var allServerKeep time.Time
140		specialServerKeep := make(map[uint64]time.Time)
141		var specialServerIDs []uint64
142		var alerts []model.AlertRule
143		DB.Find(&alerts)
144		for _, alert := range alerts {
145			for _, rule := range alert.Rules {
146				// 是不是流量记录规则
147				if !rule.IsTransferDurationRule() {
148					continue
149				}
150				dataCouldRemoveBefore := rule.GetTransferDurationStart().UTC()
151				// 判断规则影响的机器范围
152				if rule.Cover == model.RuleCoverAll {
153					// 更新全局可以清理的数据点
154					if allServerKeep.IsZero() || allServerKeep.After(dataCouldRemoveBefore) {
155						allServerKeep = dataCouldRemoveBefore
156					}
157				} else {
158					// 更新特定机器可以清理数据点
159					for id := range rule.Ignore {
160						if specialServerKeep[id].IsZero() || specialServerKeep[id].After(dataCouldRemoveBefore) {
161							specialServerKeep[id] = dataCouldRemoveBefore
162							specialServerIDs = append(specialServerIDs, id)
163						}
164					}
165				}
166			}
167		}
168		for id, couldRemove := range specialServerKeep {
169			DB.Unscoped().Delete(&model.Transfer{}, "server_id = ? AND datetime(`created_at`) < datetime(?)", id, couldRemove)
170		}
171		if allServerKeep.IsZero() {
172			DB.Unscoped().Delete(&model.Transfer{}, "server_id NOT IN (?)", specialServerIDs)
173		} else {
174			DB.Unscoped().Delete(&model.Transfer{}, "server_id NOT IN (?) AND datetime(`created_at`) < datetime(?)", specialServerIDs, allServerKeep)
175		}
176	}
