 79	func SearchByID[S ~[]E, E CommonInterface](seq iter.Seq[string], x S) S {
 80		if hasPriorityList[E]() {
 81			return searchByIDPri(seq, x)
 82		}
 83	
 84		var s S
 85		for idStr := range seq {
 86			id, err := strconv.ParseUint(idStr, 10, 64)
 87			if err != nil {
 88				continue
 89			}
 90	
 91			s = appendBinarySearch(s, x, id)
 92		}
 93		return utils.IfOr(len(s) > 0, s, x)
 94	}
