 96	func hasPriorityList[T CommonInterface]() bool {
 97		var class T
 98	
 99		switch any(class).(type) {
100		case *Server:
101			return true
102		default:
103			return false
104		}
105	}
106	
107	type splitter[S ~[]E, E CommonInterface] interface {
108		// SplitList should split a sorted list into two separate lists:
109		// The first list contains elements with a priority set (DisplayIndex != 0).
110		// The second list contains elements without a priority set (DisplayIndex == 0).
111		// The original slice is not modified. If no element without a priority is found, it returns nil.
112		// Should be safe to use with a nil pointer.
113		SplitList(x S) (S, S)
114	}
115	
116	func searchByIDPri[S ~[]E, E CommonInterface](seq iter.Seq[string], x S) S {
117		var class E
118		split, ok := any(class).(splitter[S, E])
119		if !ok {
120			return x
121		}
122	
123		plist, list2 := split.SplitList(x)
124	
125		var clist1, clist2 S
126		for idStr := range seq {
127			id, err := strconv.ParseUint(idStr, 10, 64)
128			if err != nil {
129				continue
130			}
131	
132			clist1 = appendSearch(clist1, plist, id)
133			clist2 = appendBinarySearch(clist2, list2, id)
134		}
135	
136		l := slices.Concat(clist1, clist2)
137		return utils.IfOr(len(l) > 0, l, x)
138	}
139	
140	func appendBinarySearch[S ~[]E, E CommonInterface](x, y S, target uint64) S {
141		if i, ok := slices.BinarySearchFunc(y, target, func(e E, t uint64) int {
142			return cmp.Compare(e.GetID(), t)
143		}); ok {
144			x = append(x, y[i])
145		}
146		return x
147	}
148	
149	func appendSearch[S ~[]E, E CommonInterface](x, y S, target uint64) S {
150		if i := slices.IndexFunc(y, func(e E) bool {
151			return e.GetID() == target
152		}); i != -1 {
153			x = append(x, y[i])
154		}
155	
156		return x
157	}
