698	func delayCheck(r *ReportData, m map[uint64]*model.Server, ss *model.Service, mh *pb.TaskResult) {
699		if !ss.LatencyNotify {
700			return
701		}
702	
703		notificationGroupID := ss.NotificationGroupID
704		minMuteLabel := NotificationMuteLabel.ServiceLatencyMin(mh.GetId())
705		maxMuteLabel := NotificationMuteLabel.ServiceLatencyMax(mh.GetId())
706		if mh.Delay > ss.MaxLatency {
707			// 延迟超过最大值
708			reporterServer := m[r.Reporter]
709			msg := Localizer.Tf("[Latency] %s %2f > %2f, Reporter: %s", ss.Name, mh.Delay, ss.MaxLatency, reporterServer.Name)
710			go NotificationShared.SendNotification(notificationGroupID, msg, minMuteLabel)
711		} else if mh.Delay < ss.MinLatency {
712			// 延迟低于最小值
713			reporterServer := m[r.Reporter]
714			msg := Localizer.Tf("[Latency] %s %2f < %2f, Reporter: %s", ss.Name, mh.Delay, ss.MinLatency, reporterServer.Name)
715			go NotificationShared.SendNotification(notificationGroupID, msg, maxMuteLabel)
716		} else {
717			// 正常延迟， 清除静音缓存
718			NotificationShared.UnMuteNotification(notificationGroupID, minMuteLabel)
719			NotificationShared.UnMuteNotification(notificationGroupID, maxMuteLabel)
720		}
721	}
