723	func notifyCheck(r *ReportData, m map[uint64]*model.Server,
724		ss *model.Service, mh *pb.TaskResult, lastStatus, stateCode uint8) {
725		// 判断是否需要发送通知
726		isNeedSendNotification := ss.Notify && (lastStatus != 0 || stateCode == StatusDown)
727		if isNeedSendNotification {
728			reporterServer := m[r.Reporter]
729			notificationGroupID := ss.NotificationGroupID
730			notificationMsg := Localizer.Tf("[%s] %s Reporter: %s, Error: %s", StatusCodeToString(stateCode), ss.Name, reporterServer.Name, mh.Data)
731			muteLabel := NotificationMuteLabel.ServiceStateChanged(mh.GetId())
732	
733			// 状态变更时，清除静音缓存
734			if stateCode != lastStatus {
735				NotificationShared.UnMuteNotification(notificationGroupID, muteLabel)
736			}
737	
738			go NotificationShared.SendNotification(notificationGroupID, notificationMsg, muteLabel)
739		}
740	
741		// 判断是否需要触发任务
742		isNeedTriggerTask := ss.EnableTriggerTask && lastStatus != 0
743		if isNeedTriggerTask {
744			reporterServer := m[r.Reporter]
745			if stateCode == StatusGood && lastStatus != stateCode {
746				// 当前状态正常 前序状态非正常时 触发恢复任务
747				go CronShared.SendTriggerTasks(ss.RecoverTriggerTasks, reporterServer.ID, ss.UserID)
748			} else if lastStatus == StatusGood && lastStatus != stateCode {
749				// 前序状态正常 当前状态非正常时 触发失败任务
750				go CronShared.SendTriggerTasks(ss.FailTriggerTasks, reporterServer.ID, ss.UserID)
751			}
752		}
753	}
